import React from 'react';

const Unauthorized = () => {
  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      minHeight: '100vh',
      textAlign: 'center',
      padding: '2rem'
    }}>
      <h1 style={{ fontSize: '4rem', margin: '0', color: '#ffc107' }}>403</h1>
      <h2 style={{ margin: '1rem 0', color: '#2c3e50' }}>Không có quyền truy cập</h2>
      <p style={{ color: '#6c757d', marginBottom: '2rem' }}>
        Bạn không có quyền truy cập vào trang này. Vui lòng liên hệ quản trị viên.
      </p>
      <button 
        onClick={() => window.location.href = '/'}
        style={{
          background: '#007bff',
          color: 'white',
          border: 'none',
          padding: '0.75rem 1.5rem',
          borderRadius: '0.5rem',
          cursor: 'pointer'
        }}
      >
        Về trang chủ
      </button>
    </div>
  );
};

export default Unauthorized;
